export type View = 'home' | 'badge' | 'admin';

import React, { useState, useEffect } from 'react';
import { ChevronLeft, ArrowRight, LayoutDashboard, Database, Cpu } from 'lucide-react';
import { View, Attendee } from './types';
import BadgeView from './components/BadgeView';
import AdminDashboard from './components/AdminDashboard';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('home');
  const [activeAttendee, setActiveAttendee] = useState<Attendee | null>(null);

  useEffect(() => {
    const handleHashChange = () => {
      const hash = window.location.hash.replace('#', '') as View;
      if (['home', 'badge', 'admin'].includes(hash)) {
        setCurrentView(hash);
      }
    };
    window.addEventListener('hashchange', handleHashChange);
    return () => window.removeEventListener('hashchange', handleHashChange);
  }, []);

  const navigate = (view: View, attendee?: Attendee) => {
    if (attendee) setActiveAttendee(attendee);
    setCurrentView(view);
    window.location.hash = view;
  };

  const renderContent = () => {
    switch (currentView) {
      case 'home':
        return (
          <div className="px-6 py-10 animate-in fade-in duration-700">
            {/* 头部 Slogan */}
            <div className="mb-12">
              <div className="w-14 h-14 bg-blue-600 rounded-2xl flex items-center justify-center mb-6 shadow-xl shadow-blue-100">
                <Cpu className="text-white w-7 h-7" />
              </div>
              <h1 className="text-3xl font-black text-slate-900 tracking-tight mb-2">轻彩破界 智胜未来</h1>
              <p className="text-slate-400 font-medium">2026 爱普生喷墨打印机合作伙伴大会</p>
            </div>

            {/* 场景入口: 数据中心 - 唯一保留的模块 */}
            <div className="mt-8">
              <h2 className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] mb-4 flex items-center gap-2">
                <Database size={14} className="text-indigo-400" />
                数据中枢管理 · ADMIN CONSOLE
              </h2>
              <div className="grid gap-3">
                <button onClick={() => navigate('admin')} className="group flex items-center p-8 bg-white border border-slate-200 border-dashed rounded-[2.5rem] active:scale-95 transition-all text-left shadow-sm">
                  <div className="p-5 bg-indigo-50 text-indigo-600 rounded-2xl mr-5 group-hover:bg-indigo-600 group-hover:text-white transition-colors">
                    <LayoutDashboard size={28} />
                  </div>
                  <div className="flex-1">
                    <div className="flex items-center gap-2">
                      <h3 className="font-black text-slate-800 text-lg">萝卜后台管理</h3>
                      <span className="px-2 py-0.5 bg-slate-100 text-slate-400 text-[8px] font-black rounded uppercase">Web Admin</span>
                    </div>
                    <p className="text-xs text-slate-400 mt-1 font-medium">名单导入、报表导出及专业证件打印</p>
                  </div>
                  <ArrowRight size={20} className="text-slate-200 group-hover:text-indigo-600 transition-colors" />
                </button>
              </div>
            </div>

            <div className="mt-24 flex flex-col items-center">
              <div className="w-10 h-1 bg-slate-200 rounded-full mb-6"></div>
              <p className="text-[10px] font-black text-slate-300 uppercase tracking-[0.4em]">Powered by Epson Robo-Conf System</p>
            </div>
          </div>
        );
      case 'badge': 
        if (activeAttendee) {
          return <BadgeView attendee={activeAttendee} onBack={() => navigate('home')} />;
        }
        navigate('home');
        return null;
      case 'admin': return <AdminDashboard onBack={() => navigate('home')} />;
      default: return null;
    }
  };

  return (
    <div className="max-w-md mx-auto min-h-screen bg-slate-50 overflow-x-hidden pb-10">
      {currentView !== 'home' && (
        <header className="sticky top-0 z-50 glass-effect h-14 flex items-center px-4">
           <button onClick={() => navigate('home')} className="p-2 -ml-2 text-slate-600 hover:bg-slate-100 rounded-full transition-colors">
             <ChevronLeft size={24} />
           </button>
           <h2 className="flex-1 text-center font-black text-slate-800 mr-8 text-sm tracking-tight">
             {currentView === 'badge' ? '萝卜电子证件' : '萝卜会议管理后台'}
           </h2>
        </header>
      )}
      {renderContent()}
    </div>
  );
};

export default App;

