                       <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></div>
                       <span className="text-[10px] font-black uppercase tracking-widest">已完成现场报到</span>
                    </div>
                  ) : (
                    <div className="flex items-center gap-2 text-slate-300">
                       <div className="w-2 h-2 bg-slate-200 rounded-full"></div>
                       <span className="text-[10px] font-black uppercase tracking-widest">待报到</span>
                    </div>
                  )}
                </td>
                <td className="px-8 py-6 text-right">
                  <div className="flex items-center justify-end gap-3 opacity-0 group-hover:opacity-100 transition-all transform translate-x-2 group-hover:translate-x-0">
                    <button 
                      onClick={() => onPreview?.(attendee)}
                      className="p-3 bg-white border border-slate-200 text-slate-400 rounded-2xl hover:text-[#001c71] hover:border-[#001c71] transition-all"
                      title="预览详情"
                    >
                      <Eye size={16} />
                    </button>
                    {attendee.status === 'pending' ? (
                      <button 
                        onClick={() => handleManualCheckIn(attendee)}
                        className="flex items-center gap-2 px-5 py-3 bg-[#001c71] text-white rounded-2xl text-[11px] font-black hover:bg-blue-800 shadow-xl shadow-blue-100 disabled:opacity-50"
                        disabled={loadingId === attendee.id}
                      >
                        {loadingId === attendee.id ? <Loader2 size={14} className="animate-spin" /> : <UserCheck size={14} />}
                        办理报到
                      </button>
                    ) : (
                      <button 
                        onClick={() => handlePrintBadge(attendee)}
                        className="flex items-center gap-2 px-5 py-3 bg-emerald-600 text-white rounded-2xl text-[11px] font-black hover:bg-emerald-700 shadow-xl shadow-emerald-100"
                      >
                        <Printer size={14} />
                        补印证件
                      </button>
                    )}
                    <button className="p-3 hover:bg-slate-200 rounded-2xl text-slate-400"><MoreVertical size={16} /></button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        {filtered.length === 0 && (
          <div className="py-32 text-center text-slate-300">
            <Search size={64} className="mx-auto mb-6 opacity-10" />
            <p className="text-sm font-black uppercase tracking-[0.4em]">未发现匹配的参会嘉宾</p>
          </div>
        )}
      </div>
    </div>
  );
};

