            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full pl-16 pr-6 py-5 bg-slate-100 border-none rounded-[1.5rem] text-sm font-black focus:ring-4 focus:ring-[#001c71]/5 outline-none transition-all shadow-inner"
          />
