        <div className="flex items-center gap-4 w-full md:w-auto">
           <button onClick={handleReset} className="flex-1 md:flex-none flex items-center justify-center gap-2 px-6 py-5 bg-white border border-slate-200 rounded-[1.5rem] text-xs font-black text-slate-500 hover:bg-slate-50 transition-all">
             <RefreshCcw size={16} /> 重置系统
           </button>
           <button className="flex-1 md:flex-none flex items-center justify-center gap-2 px-8 py-5 bg-[#001c71] text-white rounded-[1.5rem] text-xs font-black hover:bg-blue-800 shadow-xl shadow-blue-100 transition-all">
             <Download size={16} /> 导出报表
           </button>
        </div>
      </div>

      {/* 名单表格 */}
      <div className="bg-white rounded-[2rem] border border-slate-100 shadow-xl overflow-hidden shadow-slate-200/30">
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className="bg-slate-50/50 border-b border-slate-100">
              <th className="px-10 py-6 text-[11px] font-black text-slate-400 uppercase tracking-widest">嘉宾详情</th>
              <th className="px-10 py-6 text-[11px] font-black text-slate-400 uppercase tracking-widest text-center">报到状态</th>
              <th className="px-10 py-6 text-[11px] font-black text-slate-400 uppercase tracking-widest text-right">现场操作</th>
            </tr>
          </thead>
