        {filtered.length === 0 && (
          <div className="py-32 text-center text-slate-300">
            <Search size={64} className="mx-auto mb-6 opacity-5" />
            <p className="text-sm font-black uppercase tracking-[0.5em]">未发现匹配的参会名单</p>
